export function getTermBySlug(slug: string): EquityTerm | undefined {
  return equityTerms.find((t) => t.slug === slug);
}

export function getTermsByCategory(category: string): EquityTerm[] {
  return equityTerms.filter((t) => t.category === category);
}

export function searchTerms(query: string): EquityTerm[] {
  const q = query.toLowerCase();
  return equityTerms.filter(
    (t) =>
      t.term.toLowerCase().includes(q) ||
      t.definition.toLowerCase().includes(q) ||
      t.slug.includes(q)
  );
}
